+    ms->conns[ci].occupied = 1;
+    ms->conns[ci].closed_a = 0;
+    ms->conns[ci].closed_b = 0;
+    ms->conns[ci].addr_tag = addr_tag;
+
+    /* Queue connection for the listener to accept. */
+    ms->listeners[li].pending_conn = ci;
