+
+static asx_status mem_accept(void *state, asx_transport_listener listener,
+                             asx_transport_conn *out) {
+    asx_mem_transport_state *ms = (asx_mem_transport_state *)state;
+    uint32_t li = listener.id - 1;
+    uint32_t ci;
