+    if (slot->closed_a && slot->closed_b) { return ASX_E_DISCONNECTED; }
+
+    /* Write to a_to_b (side A convention). */
+    n = ring_write(&slot->a_to_b, data, data_len);
+    *bytes_written = n;
+    ms->total_bytes_written += n;
