+/* ------------------------------------------------------------------ */
+/* Framed transport — length-prefixed message framing                  */
+/* ------------------------------------------------------------------ */
+
+void asx_framed_transport_init(asx_framed_transport_state *state, asx_transport inner,
+                               asx_transport_conn conn) {
+    state->inner = inner;
+    state->conn = conn;
