+/* ================================================================== */
+/* Operator report tests                                               */
+/* ================================================================== */
+
+TEST(remote_report_summarizes_active_execution) {
+    asx_spawn_request req;
+    asx_spawn_ack ack;
+    asx_remote_handle handle;
+    asx_idempotency_key key;
+    asx_idempotency_record rec;
+    asx_lease lease;
+    asx_saga saga;
+    asx_remote_cap cap;
